import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';
import './CreateCombinedMaterial.css';

const LaborHoursRecord = ({
    fetchAPI,
    apiBaseUrl,
    employees
}) => {
    const [error, setError] = useState(null);
    const [projects, setProjects] = useState([]);
    const [dayRecords, setDayRecords] = useState({});
    const [selectedEmployee, setSelectedEmployee] = useState(null);

    const fetchData = useCallback(async () => {
        try {
            const projectsResponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
            setProjects(projectsResponse || []);
        } catch (error) {
            console.error('Error fetching data:', error);
            setError(error.message || 'Failed to fetch data');
        }
    }, [fetchAPI, apiBaseUrl]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const selectEmployee = (employeeId) => {
        setSelectedEmployee(employeeId);
        if (!dayRecords[employeeId]) {
            setDayRecords(prevRecords => ({
                ...prevRecords,
                [employeeId]: { employeeid: employees.find(e => e.empid === employeeId), projectid: '', start: '', end: '' }
            }));
        }
    };

    const handleChange = (employeeId, field, value) => {
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                [field]: value,
            }
        }));
    };

    const saveDayRecord = async (employeeId) => {
        try {
            const employeeRecord = dayRecords[employeeId];
            const response = await fetchAPI(`${apiBaseUrl}/laborhoursAPI`, {
                method: 'POST',
                body: JSON.stringify(employeeRecord)
            });
            console.log('Save successful:', response);
        } catch (error) {
            console.error('Failed to save labor hours:', error);
            setError('Failed to save labor hours');
        }
    };

    if (error) {
        return <div>Error: {error}</div>;
    }

    return (
        <div className="material-input-form-container">
            <div className="employee-list">
                {employees.map(employee => (
                    <button
                        key={employee.empid}
                        className={`employee-button ${selectedEmployee === employee.empid ? 'active' : ''}`}
                        onClick={() => selectEmployee(employee.empid)}
                    >
                        {employee.name}
                    </button>
                ))}
            </div>
            {selectedEmployee && (
                <div className="material-input-form">
                    <h3>Day Record for {dayRecords[selectedEmployee].name}</h3>
                    <button className="close-popup" onClick={() => setSelectedEmployee(null)}>×</button>
                    <div className="form-row">
                        <div className="form-group">
                            <label>Project:</label>
                            <Select
                                name="projectid"
                                value={projects.find(project => project.prid === dayRecords[selectedEmployee]?.projectid) ? { value: dayRecords[selectedEmployee].projectid, label: projects.find(project => project.prid === dayRecords[selectedEmployee].projectid).name } : null}
                                options={projects.map(project => ({
                                    value: project.prid,
                                    label: project.name,
                                }))}
                                onChange={e => handleChange(selectedEmployee, 'projectid', e.value)}
                                placeholder="Select a Project"
                                required
                            />
                        </div>
                        <div className="form-group">
                            <label htmlFor={`start-${selectedEmployee}`}>Start Time</label>
                            <input
                                id={`start-${selectedEmployee}`}
                                type="time"
                                name="start"
                                value={dayRecords[selectedEmployee].start}
                                onChange={e => handleChange(selectedEmployee, 'start', e.target.value)}
                                placeholder="HH:MM"
                                className="form-control"
                            />
                        </div>
                        <div className="form-group">
                            <label htmlFor={`end-${selectedEmployee}`}>End Time</label>
                            <input
                                id={`end-${selectedEmployee}`}
                                type="time"
                                name="end"
                                value={dayRecords[selectedEmployee].end}
                                onChange={e => handleChange(selectedEmployee, 'end', e.target.value)}
                                placeholder="HH:MM"
                                className="form-control"
                            />
                        </div>
                    </div>
                    <button onClick={() => saveDayRecord(selectedEmployee)} className="btn btn-success save-btn">Save Day Record</button>
                </div>
            )}
        </div>
    );
};

export default LaborHoursRecord;
